import React from "react";
import { motion, useAnimation } from "framer-motion";
import { useInView } from "react-intersection-observer";

const About = (props) => {
  const controls = useAnimation();
  const [ref, inView] = useInView({
    threshold: 0.3,        // 🔥 improved trigger
    triggerOnce: true
  });

  React.useEffect(() => {
    if (inView) {
      controls.start({ opacity: 1, y: 0 });
    }
  }, [inView, controls]);

  let sectionName, hello, about;

  if (props.resumeBasicInfo) {
    sectionName = props.resumeBasicInfo.section_name.about;
    hello = props.resumeBasicInfo.description_header;
    about = props.resumeBasicInfo.description;
  }

  return (
    <section id="about" ref={ref}>

      <div className="col-md-12">

        {/* 🔥 Animated Title */}
        <motion.h1
          style={{ color: "black", textAlign: "center" }}
          initial={{ opacity: 0, y: 30 }}
          animate={controls}
          transition={{ duration: 0.5 }}
        >
          <span>{sectionName}</span>
        </motion.h1>

        <div className="row center mx-auto mb-5">
          <div className="col-md-8 mx-auto">

            {/* 🔥 Card Animation */}
            <motion.div
              className="card"
              initial={{ opacity: 0, y: 40 }}
              animate={controls}
              transition={{ duration: 0.5, delay: 0.2 }}
              whileHover={{ scale: 1.02 }}
            >

              <div className="card-header">
                <span className="iconify" data-icon="emojione:red-circle"></span>
                &nbsp;
                <span className="iconify" data-icon="twemoji:yellow-circle"></span>
                &nbsp;
                <span className="iconify" data-icon="twemoji:green-circle"></span>
              </div>

              {/* 🔥 Text Fade Animation */}
              <motion.div
                className="card-body font-trebuchet text-justify ml-3 mr-3"
                initial={{ opacity: 0 }}
                animate={controls}
                transition={{ duration: 0.5, delay: 0.4 }}
                style={{
                  height: "auto",
                  fontSize: "132%",
                  lineHeight: "200%",
                  paddingBottom: "40px"
                }}
              >
                <br />
                <span className="wave">{hello} :)</span>
                <br />
                <br />
                {about}
              </motion.div>

            </motion.div>

          </div>
        </div>

      </div>

    </section>
  );
};

export default About;
